using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI N = 1e3 + 5, M = 1e5 + 5;
int n, p, tot;
int head[N], to[M], val[M], nxt[M];
int a[N], b[N];

struct rec
{
	int c, u;
} node[N];
queue<int>q;
void add(int x, int y, int z)
{
	to[++tot] = y;
	val[tot] = z;
	nxt[tot] = head[x];
	head[x] = tot;
}
void topsort()
{
	for (int i = 1; i <= n; i++)
		if (!a[i])
			q.push(i);
	while (q.size())
	{
		int x = q.front();
		q.pop();
		for (int i = head[x]; i; i = nxt[i])
		{
			int y = to[i];
			if (node[x].c > 0)
				node[y].c += node[x].c * val[i];
			if (!--a[y])q.push(y);
		}
	}
}
signed main(void)
{
	scanf("%lld%lld", &n, &p);
	for (int i = 1; i <= n; i++)
		scanf("%lld%lld", &node[i].c, &node[i].u);
	for (int i = 1, x, y, z; i <= p; i++)
	{
		scanf("%lld%lld%lld", &x, &y, &z);
		add(x, y, z);
		a[y]++;
		b[x]++;
	}
	for (int i = 1; i <= n; i++)
		if (a[i])node[i].c -= node[i].u;
	topsort();
	int flag = 0;
	for (int i = 1; i <= n; i++)
	{
		if (!b[i] && node[i].c > 0)
		{
			printf("%lld %lld\n", i, node[i].c);
			flag = 1;
		}
	}
	if (!flag)
		puts("NULL");
	return false;
}
